-- DESE Student Restraint Data — School-Level Records
-- Regenerated from Excel source files (data/raw/dese-restraint/)
-- Years: 2016-17 through 2024-25
-- Generated automatically — do not edit by hand

SET NAMES utf8mb4;

CREATE TABLE IF NOT EXISTS restraint_data (
    id INT AUTO_INCREMENT PRIMARY KEY,
    school_year VARCHAR(10) NOT NULL,
    district_name VARCHAR(255),
    district_code VARCHAR(20),
    school_name VARCHAR(255),
    school_code VARCHAR(20),
    enrollment INT,
    students_restrained INT,
    students_restrained_suppressed TINYINT(1) DEFAULT 0,
    total_restraints INT,
    total_restraints_suppressed TINYINT(1) DEFAULT 0,
    total_injuries INT,
    total_injuries_suppressed TINYINT(1) DEFAULT 0,
    restraint_rate_per_100 DECIMAL(12,4),
    injuries_per_restraint DECIMAL(12,4),
    is_summary_row TINYINT(1) DEFAULT 0,
    source_workbook VARCHAR(255),
    INDEX idx_year (school_year),
    INDEX idx_district (district_code),
    INDEX idx_school (school_code)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


